  var fontBtn    = C.querySelector('.ink-font-btn');
  var fontWrap   = C.querySelector('.ink-font-wrap');
  var fontSlider = C.querySelector('.ink-font-slider');
  var fontVal    = C.querySelector('.ink-font-val');

  /* ── Parse meta & tags ── */
  var rawMeta = (C.dataset.meta||'').split('|');
  var mDate=rawMeta[0]||'', mWeek=rawMeta[1]||'', mTime=rawMeta[2]||'',
      mLoc=rawMeta[3]||'',  mSubLoc=rawMeta[4]||'', mWeather=rawMeta[5]||'';
  var rawTags = (C.dataset.tags||'').split('|');

  var mh='';
  if(mDate)    mh+='<span class="ink-meta-item"><span class="ink-meta-label">Date</span>'+mDate+' '+mWeek+'</span>';
  if(mTime)    mh+='<span class="ink-meta-item"><span class="ink-meta-label">Time</span>'+mTime+'</span>';
  var loc=mLoc+(mSubLoc?' · '+mSubLoc:'');
  if(loc)      mh+='<span class="ink-meta-item"><span class="ink-meta-label">Loc</span>'+loc+'</span>';
  if(mWeather) mh+='<span class="ink-meta-item"><span class="ink-meta-label">Weather</span>'+mWeather+'</span>';
  if(metaEl) metaEl.innerHTML=mh;

  if(tagsEl){
    tagsEl.innerHTML='';
    rawTags.forEach(function(t){
      t=t.trim();if(!t)return;
      var s=document.createElement('span');s.className='ink-tag';s.textContent=t;
      tagsEl.appendChild(s);
    });
  }

  /* ── Xác định khung giờ ── */
  function getTimeSlot(s){
    var m=s.match(/(\d{1,2})/);if(!m)return'night';
    var h=parseInt(m[1]);
    if(h>=5&&h<8)  return'dawn';
    if(h>=8&&h<12) return'morning';
    if(h>=12&&h<14)return'noon';
    if(h>=14&&h<18)return'afternoon';
    if(h>=18&&h<21)return'dusk';
    return'night';
  }
  var timeSlot=getTimeSlot(mTime);

  /* ── Xác định loại thời tiết ── */
  function getWeather(s){
    var w=s.toLowerCase();
    if(/sấm|bão|storm|thunder|heavy|mưa rào|mưa to/.test(w)) return'storm';
    if(/mưa|rain|drizzle|shower/.test(w))  return'rain';
    if(/tuyết|snow|blizzard/.test(w))      return'snow';
    if(/sương mù|fog|mist/.test(w))        return'fog';
    if(/gió mạnh|gale|storm wind/.test(w)) return'windy';
    if(/gió|wind/.test(w))                 return'windy';
    if(/âm u|overcast|nhiều mây/.test(w))  return'cloudy';
    if(/nắng|sunny|clear/.test(w))         return'sunny';
    if(/hoàng hôn|chiều tà|sunset|dusk/.test(w)) return'sunset';
    return'none';
  }
  var weatherType=getWeather(mWeather);

  /* ── Helper ── */
  function R(a,b){return a+Math.random()*(b-a)}

  function mk(cls,css){
    var d=document.createElement('div');
    d.className=cls;
    d.style.cssText='will-change:transform,opacity;'+css;
    wfx.appendChild(d);
    return d;
  }

  /* ── Sinh hiệu ứng thời tiết ── */
  function genWeather(){
    if(!wfx)return;
    wfx.innerHTML='';

    switch(weatherType){

      /* 🌅 Hoàng hôn (Sunset) */
      case'sunset':
        for(var i=0;i<6;i++){
          var w=R(35,75);
          mk('wx-sun-beam',
            'position:absolute;top:0;bottom:0;' +
            'left:'+R(2,90)+'%;width:'+w+'px;' +
            'background:linear-gradient(108deg,transparent 0%,rgba(255,140,50,.18) 48%,rgba(255,160,70,.22) 50%,rgba(255,140,50,.18) 52%,transparent 100%);' +
            'animation-duration:'+R(4,8)+'s;' +
            'animation-delay:'+R(0,6)+'s');
        }
        for(var i=0;i<10;i++){
          var sz=R(2,3.5);
          mk('wx-dot',
            'left:'+R(4,94)+'%;top:'+R(5,88)+'%;' +
            'width:'+sz+'px;height:'+sz+'px;' +
            'background:rgba(255,180,90,.95);' +
            'animation-duration:'+R(2,5)+'s;' +
            'animation-delay:'+R(0,7)+'s');
        }
        break;

      /* ☀️ Nắng — vệt sáng xéo + lấp lánh nhỏ */
      case'sunny':
        for(var i=0;i<6;i++){
          var w=R(35,75);
          mk('wx-sun-beam',
            'position:absolute;top:0;bottom:0;' +
            'left:'+R(2,90)+'%;width:'+w+'px;' +
            'animation-duration:'+R(4,8)+'s;' +
            'animation-delay:'+R(0,6)+'s');
        }
        for(var i=0;i<10;i++){
          var sz=R(2,3.5);
          mk('wx-dot',
            'left:'+R(4,94)+'%;top:'+R(5,88)+'%;' +
            'width:'+sz+'px;height:'+sz+'px;' +
            'animation-duration:'+R(2,5)+'s;' +
            'animation-delay:'+R(0,7)+'s');
        }
        break;

      /* 🌧 Mưa nhẹ — 12 sợi */
      case'rain':
        for(var i=0;i<12;i++){
          mk('wx-rain',
            'left:'+R(0,99)+'%;height:'+R(18,28)+'px;' +
            'opacity:'+R(.35,.6)+';' +
            'animation-duration:'+R(.55,1)+'s;' +
            'animation-delay:'+R(0,2)+'s');
        }
        break;

      /* ⛈ Bão — 20 sợi + chớp */
      case'storm':
        for(var i=0;i<20;i++){
          mk('wx-rain',
            'left:'+R(0,99)+'%;height:'+R(22,35)+'px;' +
            'opacity:'+R(.5,.8)+';' +
            'animation-duration:'+R(.3,.6)+'s;' +
            'animation-delay:'+R(0,1.5)+'s');
        }
        mk('wx-flash','position:absolute;inset:0;animation-duration:7s');
        mk('wx-flash','position:absolute;inset:0;animation-duration:11s;animation-delay:4s');
        break;

      /* ❄️ Tuyết — 10 bông */
      case'snow':
        for(var i=0;i<10;i++){
          var sz=R(3,6);
          mk('wx-snow',
            'left:'+R(0,95)+'%;' +
            'width:'+sz+'px;height:'+sz+'px;' +
            '--dx:'+R(-18,28)+'px;' +
            'opacity:'+R(.4,.75)+';' +
            'animation-duration:'+R(4,9)+'s;' +
            'animation-delay:'+R(0,6)+'s');
        }
        break;

      /* 🌫 Sương mù — 4 dải ngang */
      case'fog':
        for(var i=0;i<4;i++){
          mk('wx-fog',
            'top:'+R(8,72)+'%;' +
            'width:'+R(50,75)+'%;height:'+R(18,36)+'px;' +
            'animation-duration:'+R(16,26)+'s;' +
            'animation-delay:'+R(0,12)+'s');
        }
        break;

      /* ☁️ Nhiều mây — 2 dải mờ hơn */
      case'cloudy':
        for(var i=0;i<2;i++){
          mk('wx-fog',
            'top:'+R(15,60)+'%;' +
            'width:'+R(45,65)+'%;height:'+R(14,24)+'px;' +
            'opacity:.5;' +
            'animation-duration:'+R(20,32)+'s;' +
            'animation-delay:'+R(0,14)+'s');
        }
        break;

      /* 💨 Gió — 10 vệt ngang */
      case'windy':
        for(var i=0;i<10;i++){
          mk('wx-wind',
            'top:'+R(4,93)+'%;' +
            'animation-duration:'+R(1.4,2.6)+'s;' +
            'animation-delay:'+R(0,4)+'s');
        }
        break;
    }

    /* ⭐ Đêm luôn có sao, bất kể thời tiết */
    if(timeSlot==='night'||timeSlot==='dawn'){
      var n=timeSlot==='night'?14:6;
      for(var i=0;i<n;i++){
        var sz=R(1.5,2.8);
        mk('wx-dot star',
          'left:'+R(2,96)+'%;top:'+R(2,68)+'%;' +
          'width:'+sz+'px;height:'+sz+'px;' +
          'animation-duration:'+R(2,5)+'s;' +
          'animation-delay:'+R(0,5)+'s');
      }
    }
  }

  genWeather();

  /* ── Theme (day / night mặc định) ── */
  var LS=localStorage;

  /* Đọc trạng thái đã lưu; mặc định là dark (night) */
  var isDay=(LS.getItem('ink_theme')==='day');
  if(isDay) C.classList.add('day');
  updateToggleIcon();
  applyAccent();

  toggleBtn.onclick=function(){
    isDay=!isDay;
    C.classList.toggle('day',isDay);
    LS.setItem('ink_theme',isDay?'day':'night');
    updateToggleIcon();applyAccent();
  };

  function updateToggleIcon(){
    toggleBtn.textContent=isDay?'☾':'☼';
    toggleBtn.title=isDay?'Chuyển sang đêm':'Chuyển sang ngày';
  }

  function hexToRGB(h){
    return{r:parseInt(h.slice(1,3),16),g:parseInt(h.slice(3,5),16),b:parseInt(h.slice(5,7),16)};
  }

  function applyAccent(){
    var dayC  = LS.getItem('ink_day_color')  ||'#5a3e28';
    var nightC= LS.getItem('ink_night_color')||'#d4b483';
    var color = isDay?dayC:nightC;
    C.style.setProperty('--ink-accent',color);
    if(picker)picker.value=color;
  }

  function setColor(hex){
    LS.setItem(isDay?'ink_day_color':'ink_night_color',hex);
    applyAccent();
  }

  colorBtn.onclick=function(e){e.stopPropagation();colorWrap.classList.toggle('open');fontWrap.classList.remove('open')};
  presets.forEach(function(b){b.onclick=function(){setColor(this.dataset.c)}});
  if(picker){
    picker.addEventListener('input',function(){setColor(this.value)});
    picker.addEventListener('change',function(){setColor(this.value)});
  }

  /* ── Cỡ chữ ── */
  function applyFontScale(v){
    C.style.setProperty('--ink-fs',v/100);
    if(fontVal)fontVal.textContent=v+'%';
    if(fontSlider)fontSlider.value=v;
  }
  var savedFs=LS.getItem('ink_font_scale');
  if(savedFs)applyFontScale(parseInt(savedFs));

  fontBtn.onclick=function(e){e.stopPropagation();fontWrap.classList.toggle('open');colorWrap.classList.remove('open')};
  if(fontSlider){
    fontSlider.addEventListener('input',function(){
      var v=parseInt(this.value);
      LS.setItem('ink_font_scale',v);
      applyFontScale(v);
    });
  }

  document.addEventListener('click',function(e){
    if(colorWrap&&!colorWrap.contains(e.target))colorWrap.classList.remove('open');
    if(fontWrap &&!fontWrap.contains(e.target)) fontWrap.classList.remove('open');
  });

  C.removeAttribute('data-tags');
  C.removeAttribute('data-meta');
})();
</script>
