  // ========== Hàm tiện ích ==========
  function log(...args) { if (DEBUG) console.log('[Phồn Hoa CoT·Bản tinh giản]', ...args); }
  function getTopDocument() { try { return window.top?.document || document; } catch { return document; } }
  function getST() { return typeof SillyTavern !== 'undefined' ? SillyTavern : null; }
  function getChatArray() { const st = getST(); if (st && Array.isArray(st.chat)) return st.chat; if (Array.isArray(window.chat)) return window.chat; return null; }
  function updateBlock(messageId, message) { const st = getST(); if (st && typeof st.updateMessageBlock === 'function') { st.updateMessageBlock(messageId, message); return; } if (typeof window.updateMessageBlock === 'function') { window.updateMessageBlock(messageId, message); } }
  function escapeHtml(str) { const div = document.createElement('div'); div.textContent = str; return div.innerHTML; }

  function injectStyleOnce(doc) { if (!doc || !doc.head) return; let style = doc.getElementById(STYLE_ID); if (!style) { style = doc.createElement('style'); style.id = STYLE_ID; doc.head.appendChild(style); } style.textContent = REASONING_CSS; }
  function injectStyle() { injectStyleOnce(document); injectStyleOnce(getTopDocument()); }
  function removeStyle() { for (const doc of [document, getTopDocument()]) { const style = doc?.getElementById?.(STYLE_ID); if (style) style.remove(); } }

  // ========== Cốt lõi ==========
  function extractReasoningAndClean(text, isStreaming) {
    if (typeof text !== 'string') return null;
    const { prefix, suffix } = getReasoningConfig();
    if (text.includes(suffix)) {
      const parts = text.split(suffix);
      let reasoningPart = parts[0];
      const cleaned = parts.slice(1).join(suffix).trim();
      if (reasoningPart.includes(prefix)) reasoningPart = reasoningPart.split(prefix)[1];
      return { reasoning: reasoningPart.trim(), cleaned, state: 'done' };
    }
    return null;
  }

  function findMessageDom(messageId) {
    const selector = `#chat [mesid="${messageId}"]`;
    const inFrame = document.querySelector(selector);
    if (inFrame) return inFrame;
    const topDoc = getTopDocument();
    return topDoc?.querySelector?.(selector) || null;
  }

  // ========== Áp dụng chủ đề ==========
  function applyThemeToPanel(panel, themeKey) {
    const theme = THEMES[themeKey] || THEMES[DEFAULT_THEME_KEY];
    for (const [prop, value] of Object.entries(theme.css)) {
      panel.style.setProperty(prop, value);
    }
    // Ép trình duyệt vẽ lại (reflow), đảm bảo biến CSS có hiệu lực ngay lập tức
    void panel.offsetHeight;
  }

  function updateRadioStates(panel, themeKey) {
    const parts = themeKey.split('-');
    const mode = parts[0];
    const color = parts[1];

    const modeLight = panel.querySelector('.cot-mode-light');
    const modeDark = panel.querySelector('.cot-mode-dark');
    if (modeLight) modeLight.checked = (mode === 'light');
    if (modeDark) modeDark.checked = (mode === 'dark');

    const swatches = {
      pink: panel.querySelector('.cot-theme-pink'),
      lavender: panel.querySelector('.cot-theme-lavender'),
      mint: panel.querySelector('.cot-theme-mint'),
      crystal: panel.querySelector('.cot-theme-crystal')
    };
    for (const [key, input] of Object.entries(swatches)) {
      if (input) input.checked = (color === key);
    }
  }

  function getThemeKeyFromRadio(panel) {
    const modeDark = panel.querySelector('.cot-mode-dark');
    const mode = (modeDark && modeDark.checked) ? 'dark' : 'light';

    const colorPink = panel.querySelector('.cot-theme-pink');
    const colorLav = panel.querySelector('.cot-theme-lavender');
    const colorMint = panel.querySelector('.cot-theme-mint');
    const colorCrystal = panel.querySelector('.cot-theme-crystal');

    let color = 'lavender';
    if (colorPink?.checked) color = 'pink';
    else if (colorLav?.checked) color = 'lavender';
    else if (colorMint?.checked) color = 'mint';
    else if (colorCrystal?.checked) color = 'crystal';

    const key = `${mode}-${color}`;
    return THEMES[key] ? key : DEFAULT_THEME_KEY;
  }

  function getAllCotPanels() {
    const panels = [];
    document.querySelectorAll('.cot-panel').forEach(p => panels.push(p));
    try {
      const topDoc = getTopDocument();
      if (topDoc !== document) {
        topDoc.querySelectorAll('.cot-panel').forEach(p => panels.push(p));
      }
    } catch (_) {}
    return panels;
  }

  function refreshAllPanels(themeKey) {
    getAllCotPanels().forEach(p => {
      applyThemeToPanel(p, themeKey);
      updateRadioStates(p, themeKey);
    });
  }

  function bindThemeEvents(panel) {
    const allRadios = panel.querySelectorAll('.cot-mode-light, .cot-mode-dark, .cot-theme-pink, .cot-theme-lavender, .cot-theme-mint, .cot-theme-crystal');
    allRadios.forEach(radio => {
      const newRadio = radio.cloneNode(true);
      radio.parentNode.replaceChild(newRadio, radio);
    });
    const freshRadios = panel.querySelectorAll('.cot-mode-light, .cot-mode-dark, .cot-theme-pink, .cot-theme-lavender, .cot-theme-mint, .cot-theme-crystal');
    freshRadios.forEach(input => {
      input.addEventListener('change', () => {
        // Sử dụng độ trễ cực ngắn để đảm bảo trạng thái radio ổn định
        setTimeout(() => {
          const key = getThemeKeyFromRadio(panel);
          saveThemeKey(key);
          refreshAllPanels(key);
        }, 10);
      });
    });
  }

  // ========== Xây dựng bảng ==========
  function buildCotPanel(reasoningText, state) {
    const themeKey = loadThemeKey();
    const parts = themeKey.split('-');
    const mode = parts[0];
    const color = parts[1];

    const wrapper = document.createElement('div');
    wrapper.className = 'cot-wrapper';
    wrapper.dataset.reasoningState = state;
    const isChecked = (state === 'thinking');
    wrapper.innerHTML = `
    <div class="cot-panel" data-state="${state}">
      <div class="cot-header">
        <label class="cot-toggle" title="Mở rộng/Thu gọn suy nghĩ">
          <input type="checkbox" class="cot-checkbox" ${isChecked ? 'checked' : ''}>
          <span class="cot-header-left">
            <span class="cot-bud" aria-hidden="true">
              <svg width="34" height="34" viewBox="0 0 100 100">
                <path d="M50 70 Q20 80 10 50 Q40 40 50 70 Z" class="cot-bud-leaf-left" />
                <path d="M50 70 Q80 80 90 50 Q60 40 50 70 Z" class="cot-bud-leaf-right" />
                <circle cx="50" cy="50" r="14" class="cot-bud-core" />
                <path d="M50 50 C30 15 45 0 50 0 C55 0 70 15 50 50 Z" class="cot-bud-petal" style="--angle-closed:0deg; --angle-open:360deg; --delay:0s;" />
                <path d="M50 50 C30 15 45 0 50 0 C55 0 70 15 50 50 Z" class="cot-bud-petal" style="--angle-closed:72deg; --angle-open:432deg; --delay:.08s;" />
                <path d="M50 50 C30 15 45 0 50 0 C55 0 70 15 50 50 Z" class="cot-bud-petal" style="--angle-closed:144deg; --angle-open:504deg; --delay:.16s;" />
                <path d="M50 50 C30 15 45 0 50 0 C55 0 70 15 50 50 Z" class="cot-bud-petal" style="--angle-closed:216deg; --angle-open:576deg; --delay:.24s;" />
                <path d="M50 50 C30 15 45 0 50 0 C55 0 70 15 50 50 Z" class="cot-bud-petal" style="--angle-closed:288deg; --angle-open:648deg; --delay:.32s;" />
              </svg>
            </span>
            <span class="cot-title">
              <span class="cot-title-closed">Thu thập suy nghĩ · Tâm vận sơ thành</span>
              <span class="cot-title-open">L Ắ N G  Đ Ọ N G  S U Y  N G H Ĩ</span>
            </span>
          </span>
          <span class="cot-sparkles" aria-hidden="true"><i></i><i></i><i></i></span>
        </label>
        <form class="cot-header-badge cot-controls" onsubmit="return false;" aria-label="Chuyển đổi chủ đề Phồn Hoa">
          <label class="cot-mode-btn" title="Nền màu sáng">
            <input type="radio" name="cot-mode-${SCRIPT_ID}" class="cot-mode-light" ${mode === 'light' ? 'checked' : ''}>
            <svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="5" fill="#fb923c"/><path d="M12 2v3M12 19v3M4.9 4.9l2.1 2.1M17 17l2.1 2.1M2 12h3M19 12h3M4.9 19.1 7 17M17 7l2.1-2.1" stroke="#fb923c" stroke-width="1.8" stroke-linecap="round"/></svg>
          </label>
          <label class="cot-mode-btn" title="Nền màu tối">
            <input type="radio" name="cot-mode-${SCRIPT_ID}" class="cot-mode-dark" ${mode === 'dark' ? 'checked' : ''}>
            <svg viewBox="0 0 24 24"><path d="M18.5 15.5A7 7 0 0 1 8.5 5.5 8 8 0 1 0 18.5 15.5Z" fill="#312e81"/></svg>
          </label>
          <span class="cot-badge-divider"></span>
          <label class="cot-swatch" title="Nền Anh Đào"><input type="radio" name="cot-theme-${SCRIPT_ID}" class="cot-theme-pink" ${color === 'pink' ? 'checked' : ''}><b style="background:#f9a8d4;"></b></label>
          <label class="cot-swatch" title="Nền Oải Hương"><input type="radio" name="cot-theme-${SCRIPT_ID}" class="cot-theme-lavender" ${color === 'lavender' ? 'checked' : ''}><b style="background:#d8b4fe;"></b></label>
          <label class="cot-swatch" title="Nền Bạc Hà"><input type="radio" name="cot-theme-${SCRIPT_ID}" class="cot-theme-mint" ${color === 'mint' ? 'checked' : ''}><b style="background:#86efac;"></b></label>
          <label class="cot-swatch" title="Nền Pha Lê"><input type="radio" name="cot-theme-${SCRIPT_ID}" class="cot-theme-crystal" ${color === 'crystal' ? 'checked' : ''}><b style="background:transparent;border:2px dashed rgba(200,180,240,0.6);"></b></label>
        </form>
      </div>
      <div class="cot-content">
        <div class="cot-inner">
          <div class="cot-prose">${escapeHtml(reasoningText)}</div>
        </div>
      </div>
    </div>
    `;
    const panel = wrapper.querySelector('.cot-panel');
    applyThemeToPanel(panel, themeKey);
    bindThemeEvents(panel);
    return wrapper;
  }

  function updateCotPanel(wrapper, reasoningText, state) {
    const panel = wrapper.querySelector('.cot-panel');
    if (panel) panel.dataset.state = state;
    const checkbox = wrapper.querySelector('.cot-checkbox');
    if (checkbox && state === 'thinking' && !checkbox.checked) checkbox.checked = true;
    const prose = wrapper.querySelector('.cot-prose');
    if (prose) prose.innerHTML = escapeHtml(reasoningText);
    wrapper.dataset.reasoningState = state;
  }

  function upsertCotPanel(messageDom, reasoningText, state) {
    let wrapper = messageDom.querySelector('.cot-wrapper');
    if (!wrapper) {
      wrapper = buildCotPanel(reasoningText, state);
      const mesBlock = messageDom.querySelector('.mes_block') || messageDom;
      const mesText = mesBlock.querySelector('.mes_text');
      if (mesText) mesBlock.insertBefore(wrapper, mesText);
      else mesBlock.appendChild(wrapper);
    } else {
      const chatContainer = document.querySelector('#chat');
      const savedScroll = chatContainer ? chatContainer.scrollTop : 0;
      updateCotPanel(wrapper, reasoningText, state);
      if (chatContainer) requestAnimationFrame(() => { chatContainer.scrollTop = savedScroll; });
    }
  }

  function removeCotPanel(messageDom) {
    const wrapper = messageDom?.querySelector?.('.cot-wrapper');
    if (wrapper) wrapper.remove();
  }

  function applyReasoningToMessage(messageId) {
    const id = Number(messageId);
    if (!Number.isInteger(id) || id < 0) return;
    const chat = getChatArray();
    if (!chat) return;
    const message = chat[id];
    if (!message || message.is_user) return;
    const isStreaming = message.swipe_id === undefined && message.gen_started && !message.extra?.reasoning_duration;
    const messageDom = findMessageDom(id);
    if (!messageDom) return;
    if (message.extra?.reasoning) {
      const nativeState = message.extra?.reasoning_state;
      const state = nativeState === 'thinking' || nativeState === 'done' ? nativeState : (isStreaming ? 'thinking' : 'done');
      const { suffix } = getReasoningConfig();
      if (message.mes.includes(suffix)) {
        message.mes = message.mes.split(suffix).slice(1).join(suffix).trim();
        updateBlock(id, message);
      }
      upsertCotPanel(messageDom, message.extra.reasoning, state);
      return;
    }
    const parsed = extractReasoningAndClean(String(message.mes ?? ''), isStreaming);
    if (!parsed) { removeCotPanel(messageDom); return; }
    message.extra = (message.extra && typeof message.extra === 'object') ? message.extra : {};
    message.extra.reasoning = parsed.reasoning;
    message.extra.reasoning_type = 'parsed';
    message.extra.reasoning_state = parsed.state;
    message.mes = parsed.cleaned;
    updateBlock(id, message);
    upsertCotPanel(messageDom, parsed.reasoning, parsed.state);
  }

  function applyReasoningToAllMessages() {
    const chat = getChatArray();
    if (!chat) return;
    for (let i = 0; i < chat.length; i++) applyReasoningToMessage(i);
  }

  let streamTickRaf = 0;
  function scheduleApplyLatestAssistantMessage() {
    if (streamTickRaf) return;
    streamTickRaf = requestAnimationFrame(() => {
      streamTickRaf = 0;
      const chat = getChatArray();
      if (!chat || !chat.length) return;
      for (let i = chat.length - 1; i >= 0; i--) {
        const msg = chat[i];
        if (msg && !msg.is_user) { applyReasoningToMessage(i); break; }
      }
    });
  }

  function bindEvents() {
    if (typeof eventOn === 'function' && typeof tavern_events !== 'undefined') {
      eventOn(tavern_events.MESSAGE_UPDATED, applyReasoningToMessage);
      eventOn(tavern_events.MESSAGE_RECEIVED, applyReasoningToMessage);
      eventOn(tavern_events.CHAT_CHANGED, () => { injectConfig(); setTimeout(applyReasoningToAllMessages, 50); });
      eventOn(tavern_events.CHARACTER_MESSAGE_RENDERED, applyReasoningToMessage);
      eventOn(tavern_events.STREAM_TOKEN_RECEIVED, scheduleApplyLatestAssistantMessage);
    } else { log('eventOn/tavern_events không khả dụng'); }
  }

  function init() {
    injectConfig();
    injectStyle();
    bindEvents();
    setTimeout(applyReasoningToAllMessages, 100);
    setTimeout(applyReasoningToAllMessages, 800);
    $(window).on('pagehide', removeStyle);
    log('Bảng Phồn Hoa CoT Bản tinh giản (Không có </thinking> thì không đóng, 6 chủ đề chuyển đổi tức thời + Ghi nhớ đã được bật) đã tải xong');
  }

  $(() => init());
})();
